const functions = require('firebase-functions');
const { Client } = require('@sendgrid/client');
const twilio = require('twilio');

// SendGrid credentials
const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const SENDGRID_FROM_EMAIL = 'your-from-email@example.com';

// Twilio credentials
const TWILIO_ACCOUNT_SID = 'YOUR_TWILIO_ACCOUNT_SID';
const TWILIO_AUTH_TOKEN = 'YOUR_TWILIO_AUTH_TOKEN';
const TWILIO_PHONE_NUMBER = '+1234567890';

// Initialize SendGrid client
const sendgridClient = new Client(SENDGRID_API_KEY);

// Initialize Twilio client
const twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendEmail = functions.https.onCall((data, context) => {
  const { to, subject, text } = data;

  // Send email using SendGrid
  sendgridClient.emptyRequest()
    .setMethod('POST')
    .setUrl('/v3/mail/send')
    .addHeaders({ 'Authorization': `Bearer ${SENDGRID_API_KEY}` })
    .addBody({
      personalizations: [
        {
          to: [{ email: to, name: '' }],
          subject,
        },
      ],
      from: { email: SENDGRID_FROM_EMAIL, name: '' },
      content: [
        {
          type: 'text/plain',
          value: text,
        },
      ],
    })
    .then(response => {
      console.log('Email sent successfully:', response);
    })
    .catch(error => {
      console.error('Error sending email:', error);
    });

  // Send SMS using Twilio
  twilioClient.messages.create({
    from: TWILIO_PHONE_NUMBER,
    to: '+1234567890',
    body: text,
  })
    .then(message => {
      console.log('SMS sent successfully:', message.sid);
    })
    .catch(error => {
      console.error('Error sending SMS:', error);
    });
});